import ReactMarkdown from "react-markdown";

function Message({ role, text }) {
    return (
        <div style={{ marginBottom: 10 }}>
            <b>{role === "user" ? "You" : "AI"}:</b>
            <div style={{ paddingLeft: 10 }}>
                <ReactMarkdown>{text}</ReactMarkdown>
            </div>
        </div>
    );
}

export default Message;
